| <code><nowiki>{{convert|2|cuyd|m3</nowiki>{{bg|1=yellow|2=<nowiki>|</nowiki>disp=out<nowiki>|</nowiki>adj=on|abbr=off}}}}</code> || {{convert|2|cuyd|m3|disp=out|adj=on|abbr=off}} || output, adjective
